            line = line.strip()
            if line:
                parts = line.split('|')
                if len(parts) == 3:
                    username, password, balance = parts
                    users[username] = {'password': password, 'balance': float(balance)}
    return users


def load_listings():
    listings = {}
    with open(os.path.join(data_dir, 'listings.txt'), 'r') as f:
        for line in f:
            line = line.strip()
            if line:
                parts = line.split('|')
                if len(parts) == 7:
                    listing_id, title, description, start_price, curr_price, seller, sold_to = parts
                    listings[listing_id] = {
                        'title': title,
                        'description': description,
                        'start_price': float(start_price),
                        'curr_price': float(curr_price),
                        'seller': seller,
                        'sold_to': sold_to if sold_to else None
                    }
    return listings


def load_bids():
    bids = []
    with open(os.path.join(data_dir, 'bids.txt'), 'r') as f:
        for line in f:
            line = line.strip()
