@app.route('/home', methods=['GET', 'POST'])
def home():
    if request.method == 'POST':
        # Load featured_books with book_id only as list of dicts
        books = read_pipe_delimited_file('books.txt', BOOKS_FIELDS)
        featured_books = [{'book_id': book['book_id']} for book in books]

        # Load bestsellers_summary with bookId and sales fields
        bestsellers = read_pipe_delimited_file('bestsellers.txt', BESTSELLERS_FIELDS)
        bestsellers_summary = []
        for item in bestsellers:
            # bookId as int (convert str to int) and sales as str from sales_count
            bestsellers_summary.append({
                'bookId': int(item['book_id']),
                'sales': item['sales_count']
            })

        return render_template('dashboard.htm', featured_books=featured_books, bestsellers_summary=bestsellers_summary)
    else:
        # For GET just redirect to /home POST or return empty render
        return render_template('dashboard.htm', featured_books=[], bestsellers_summary=[])


# Route /bookcatalog
@app.route('/bookcatalog', methods=['GET'])
def bookcatalog():
    # Load books excluding price (remove price field)
    books_all = read_pipe_delimited_file('books.txt', BOOKS_FIELDS)
    books = []
    for book in books_all:
        # Exclude price field
        filtered_book = {k: book[k] for k in book if k != 'price'}
        books.append(filtered_book)

    # Load categories
    categories = read_pipe_delimited_file('categories.txt', CATEGORIES_FIELDS)

    # Selected category is passed as query param but filter disabled so just empty
    selected_category = request.args.get('category', '')

    # search only by author, title, isbn
    search_query = request.args.get('search', '')

    if search_query:
        filtered_books = []
        sq_lower = search_query.lower()
        for book in books_all:
            if (sq_lower in book['author'].lower()) or (sq_lower in book['title'].lower()) or (sq_lower in book['isbn'].lower()):
                filtered_books.append({k: book[k] for k in book if k != 'price'})
        books = filtered_books

    return render_template('catalog.htm', books=books, categories=categories, selected_category=selected_category, search_query=search_query)


