@app.route('/cart', methods=['GET', 'POST'])
def shoppingCart():
    if request.method == 'POST':
        # Process quantity updates only
        cart_items = read_pipe_delimited_file('cart.txt', CART_FIELDS)

        updates = {}
        for key in request.form:
            if key.startswith('update-qty-'):
                cart_id = key[len('update-qty-'):]
                try:
                    qty = int(request.form[key])
                    if qty < 0:
                        qty = 0
                except Exception:
                    qty = 0
                updates[cart_id] = qty

        # Update quantities in cart_items
        for item in cart_items:
            if item['cart_id'] in updates:
                item['quantity'] = str(updates[item['cart_id']])

        # Save updated cart
        write_pipe_delimited_file('cart.txt', cart_items, CART_FIELDS)

        return redirect(url_for('home'))

    # GET Method
    cart_items = read_pipe_delimited_file('cart.txt', CART_FIELDS)
    books = {b['book_id']: b for b in read_pipe_delimited_file('books.txt', BOOKS_FIELDS)}

    # Build cart_items list with computed subtotal
    display_cart_items = []
    total_amount = 0.0
    for item in cart_items:
        book = books.get(item['book_id'])
        if book:
            price = float(book['price'])
            quantity = int(item['quantity'])
            subtotal = price * quantity

            display_cart_items.append({
                'cartID': item['cart_id'],
                'bookID': book['book_id'],
                'title': book['title'],
                'quantity': str(quantity),
                'price': book['price'],
                'subtotal': f"{subtotal:.2f}"
            })
            total_amount += subtotal

    total_amount = round(total_amount, 2)
    return render_template('cart.htm', cart_items=display_cart_items, total_amount=total_amount)


