DATA_DIR = './data'

# Utility function to read delimited data files
# Fields are pipe-separated or semicolon-separated depending on file
# We will detect separator by filename or parameter

def read_data_file(filename, sep=';', fields=None):
    path = os.path.join(DATA_DIR, filename)
    data = []
    if not os.path.exists(path):
        return data
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split(sep)
            if fields and len(parts) != len(fields):
                # malformed line skip
                continue
            if fields:
                item = {fields[i]: parts[i] for i in range(len(fields))}
                data.append(item)
            else:
                data.append(parts)
    return data

# Utility function to save data files (list of dicts)
def save_data_file(filename, data_list, fields, sep=';'):
    path = os.path.join(DATA_DIR, filename)
    lines = []
    for item in data_list:
        line = sep.join(str(item[field]) for field in fields)
        lines.append(line)
    with open(path, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines))

