from flask import Flask, render_template, redirect, url_for, request
import os
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_PATH = 'data'

# --- Utility functions --- #

def load_users():
    users = {}
    path = os.path.join(DATA_PATH, 'users.txt')
    if os.path.exists(path):
        with open(path, 'r') as f:
            for line in f:
                parts = line.strip().split(',')
                if len(parts) >= 4:
                    username = parts[0]
                    email = parts[1]
                    # phone and full_name not needed for now
                    users[username] = {
                        'username': username,
                        'email': email
                    }
    return users


def load_menu():
    menus = []
    path = os.path.join(DATA_PATH, 'menu.txt')
    if os.path.exists(path):
        with open(path, 'r') as f:
            for line in f:
                parts = line.strip().split(',')
                if len(parts) >= 8:
                    # Fields per spec:
                    # dish_id, name, category, price, description, ingredients, dietary, avg_rating
                    dish_id = parts[0]
                    name = parts[1]
                    category = parts[2]
                    price = parts[3]
                    description = parts[4]
                    # ingredients, dietary unused currently
                    avg_rating = parts[7]
                    menus.append({
                        'dish_id': dish_id,
                        'name': name,
                        'category': category,
                        'price': price,
                        'description': description,
                        'avg_rating': avg_rating
                    })
    return menus


def load_reservations():
    reservations = []
    path = os.path.join(DATA_PATH, 'reservations.txt')
    if os.path.exists(path):
        with open(path, 'r') as f:
            for line in f:
                parts = line.strip().split(',')
                if len(parts) >= 10:
                    reservation_id = parts[0]
                    username = parts[1]
                    guest_name = parts[2]
                    phone = parts[3]
                    email = parts[4]
                    party_size = parts[5]
                    date = parts[6]  # MM-DD-YYYY string
                    time = parts[7]  # HH:MM string
                    special_requests = parts[8]
                    status = parts[9]
                    reservations.append({
                        'reservation_id': reservation_id,
                        'username': username,
                        'guest_name': guest_name,
                        'phone': phone,
                        'email': email,
                        'party_size': party_size,
                        'date': date,
                        'time': time,
                        'special_requests': special_requests,
                        'status': status
                    })
    return reservations


def load_waitlist():
    waitlist = []
    path = os.path.join(DATA_PATH, 'waitlist.txt')
    if os.path.exists(path):
        with open(path, 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) >= 5:
                    waitlist_id = parts[0]
                    username = parts[1]
                    party_size = parts[2]
                    join_time = parts[3]  # MM-DD-YYYY HH:MM:SS
                    status = parts[4]
                    waitlist.append({
                        'waitlist_id': waitlist_id,
                        'username': username,
                        'party_size': party_size,
                        'join_time': join_time,
                        'status': status
                    })
    return waitlist


def load_reviews():
    reviews = []
    path = os.path.join(DATA_PATH, 'reviews.txt')
    if os.path.exists(path):
        with open(path, 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) >= 6:
                    review_id = parts[0]
                    username = parts[1]
                    dish_id = parts[2]
                    rating = parts[3]
                    review_text = parts[4]
                    review_date = parts[5]
                    reviews.append({
                        'review_id': review_id,
                        'username': username,
                        'dish_id': dish_id,
                        'rating': rating,
                        'review_text': review_text,
                        'review_date': review_date
                    })
    return reviews


# --- Routes implementation --- #

@app.route('/', methods=['POST'])
def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard', methods=['POST'])
def dashboard():
    # Spec says username and featured_dishes and upcoming_reservations are context variables
    # No login or session specified, so we try get username from form or fallback to first user in users
    users = load_users()
    username = request.form.get('username')
    if not username or username not in users:
        # fallback pick first user
        username = next(iter(users), None)

    # Featured dishes: by default top 3 dishes by avg_rating (sorted descending)
    # Parse avg_rating as float for sorting
    menu = load_menu()

    def avg_rating_float(d):
        try:
            return float(d.get('avg_rating', '0'))
        except:
            return 0.0

    featured_sorted = sorted(menu, key=avg_rating_float, reverse=True)[:3]

    # Compose featured dishes list dict {dish_id int, name str, price string, description str}
    featured_dishes = []
    for d in featured_sorted:
        featured_dishes.append({
            'dish_id': int(d['dish_id']),
            'name': d['name'],
            'price': d['price'],
            'description': d['description']
        })

    # Upcoming reservations: filter all reservations by username and status Upcoming
    reservations = load_reservations()
    upcoming = []
    for r in reservations:
        if r['username'] == username and r['status'].lower() == 'upcoming':
            try:
                # convert date MM-DD-YYYY to int YYYYMMDD for template (assuming int)
                dt = datetime.datetime.strptime(r['date'], '%Y-%m-%d')
                date_int = int(dt.strftime('%Y%m%d'))
            except Exception:
                date_int = 0
            try:
                # time HH:MM to int HHMM
                time_int = int(r['time'].replace(':', ''))
            except Exception:
                time_int = 0

            upcoming.append({
                'reservation_id': r['reservation_id'],
                'date': date_int,
                'time': time_int,
                'party_size': r['party_size'],
                'status': 0 if r['status'].lower() == 'upcoming' else 1
            })

    return render_template('dashboard.htm', username=username, featured_dishes=featured_dishes, upcoming_reservations=upcoming)


