@app.route('/write-review', methods=['GET', 'POST'])
def write_reviews():
    menu = load_menu()
    dishes = []
    for m in menu:
        dishes.append({
            'dish_id': m['dish_id'],
            'name': m['name']
        })

    if request.method == 'GET':
