        # Load existing reviews to determine new review_id
        reviews = load_reviews()
        max_id = 0
        for r in reviews:
            try:
                cur_id = int(r['review_id'])
                if cur_id > max_id:
                    max_id = cur_id
            except:
                continue
        new_id = str(max_id + 1)

        # For username, use first user (no auth)
        users = load_users()
        username = next(iter(users), None) or 'guest'

        new_review = {
            'review_id': new_id,
            'username': username,
            'dish_id': dish_id,
            'rating': rating,
            'review_text': review_text,
            'review_date': datetime.datetime.now().strftime('%Y-%m-%d')
        }

        path = os.path.join(DATA_PATH, 'reviews.txt')
        with open(path, 'a') as f:
            line = '|'.join([
                new_review['review_id'],
                new_review['username'],
                new_review['dish_id'],
                new_review['rating'],
