                    low_temp_raw = parts[4].strip()
                    condition = parts[5].strip().split(',')
                    precipitation = parts[6].strip()
                    humidity = parts[7].strip()
                    # Normalizing high_temp and low_temp to int if possible
                    try:
                        high_temp = int(high_temp_raw)
                    except:
                        high_temp = high_temp_raw
                    try:
