        with open('data/alert.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    alert_id = parts[0].strip()
                    location_id = parts[1].strip()
                    alert_type = parts[2].strip().split(',')
                    severity = parts[3].strip().lower()
                    # Normalize severity by mapping textual to integer as problem states severity integer
                    severity_map = {"critical": 4, "critcal": 4, "high": 3, "med": 2, "medium": 2, "low": 1, "all": 0}
                    sev_val = severity_map.get(severity, 0)
