from flask import Flask, render_template, redirect, url_for, request
import random

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Data load functions

def load_current_weather():
    weather_data = []
    try:
        with open('data/currentweather.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 7:
                    location_id = parts[0].strip()
                    location_name = parts[1].strip()
                    temp_raw = parts[2].strip()
                    # temp can be string or int - try convert to int if possible
                    try:
                        temp = int(temp_raw)
                    except:
                        temp = temp_raw
                    condition = parts[3].strip().split(',')
                    humidity = parts[4].strip()
                    wind_speed = parts[5].strip()
                    last_updated = parts[6].strip()
                    weather_data.append({
                        'location_id': location_id,
                        'location_name': location_name,
                        'temp': temp,
                        'condition': condition,
                        'humidity': humidity,
                        'wind_speed': wind_speed,
                        'last_updated': last_updated
                    })
    except Exception as e:
        # Fail silently and return empty list if file problem
        weather_data = []
    return weather_data


def load_forecast():
    forecasts = []
    try:
        with open('data/forecast.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    forecast_id = parts[0].strip()
                    location_id = parts[1].strip()
                    date = parts[2].strip()  # Keep string format YYYY-DD-MM as stated
                    high_temp_raw = parts[3].strip()
                    low_temp_raw = parts[4].strip()
                    condition = parts[5].strip().split(',')
                    precipitation = parts[6].strip()
                    humidity = parts[7].strip()
                    # Normalizing high_temp and low_temp to int if possible
                    try:
                        high_temp = int(high_temp_raw)
                    except:
                        high_temp = high_temp_raw
                    try:
                        low_temp = int(low_temp_raw)
                    except:
                        low_temp = low_temp_raw
                    forecasts.append({
                        'forecast_id': forecast_id,
                        'location_id': location_id,
                        'date': date,
                        'high_temperature': high_temp,
                        'low_temperature': low_temp,
                        'status': condition,
                        'precipitation': precipitation,
                        'humidity': humidity,
                    })
    except Exception:
        forecasts = []
    return forecasts


def load_locations():
    locations = []
    try:
        with open('data/locationss.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    location_id = parts[0].strip()
                    location_name = parts[1].strip().split(',')
                    latitude = parts[2].strip()
                    longitude = parts[3].strip()
                    country = parts[4].strip().split(',')
                    timezone = parts[5].strip().split(',')
                    locations.append({
                        'loc_id': location_id,
                        'locationName': location_name,
                        'latitude': latitude,
                        'longitude': longitude,
                        'country': country,
                        'timezone': timezone
                    })
    except Exception:
        locations = []
    return locations


def load_alerts():
    alerts = []
    try:
        with open('data/alert.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    alert_id = parts[0].strip()
                    location_id = parts[1].strip()
                    alert_type = parts[2].strip().split(',')
                    severity = parts[3].strip().lower()
                    # Normalize severity by mapping textual to integer as problem states severity integer
                    severity_map = {"critical": 4, "critcal": 4, "high": 3, "med": 2, "medium": 2, "low": 1, "all": 0}
                    sev_val = severity_map.get(severity, 0)
                    # fallback int severity if possible
                    try:
                        sev_val = int(parts[3].strip())
                    except:
                        pass
                    description = parts[4].strip().split(',')
                    start = parts[5].strip()
                    end = parts[6].strip()
                    acknowledged_raw = parts[7].strip()
                    # acknowledged can be int 0 or 1 or string
                    try:
                        acknowledged = int(acknowledged_raw)
                    except:
                        acknowledged = [acknowledged_raw]
                    alerts.append({
                        'alertid': alert_id,
                        'location': location_id,
                        'alert_type': alert_type,
                        'severity_level': sev_val,
                        'desc': description,
                        'start': start,
                        'end': end,
                        'acknowledged': acknowledged
                    })
    except Exception:
        alerts = []
    return alerts


def load_air_quality():
    air_quality = []
    try:
        with open('data/airquality.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    aqi_id = parts[0].strip()
                    location_id = parts[1].strip()
                    index_aqi = parts[2].strip()
                    pm25 = parts[3].strip()
                    try:
                        pm10 = int(parts[4].strip())
                    except:
                        pm10 = parts[4].strip()
                    no2 = parts[5].strip()
                    o3 = parts[6].strip()
                    last_updated = parts[7].strip()
                    air_quality.append({
                        'aqi_id': aqi_id,
                        'location_id': location_id,
                        'index_aqi': index_aqi,
                        'pm25': pm25,
                        'pm10': pm10,
                        'no2': no2,
                        'o3': o3,
                        'last_updated': last_updated
                    })
    except Exception:
        air_quality = []
    return air_quality


def load_saved_locations():
    saved = []
    try:
        with open('data/savedlocations.txt', 'r') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 5:
                    saved_id = parts[0].strip()
                    user_id = parts[1].strip()
                    location_id = parts[2].strip()
                    location_name = parts[3].strip().split(',')
                    is_default_raw = parts[4].strip()
                    try:
                        is_default = int(is_default_raw)
                    except:
                        is_default = 0
                    saved.append({
                        'saved_id': saved_id,
                        'user': user_id,
                        'location_id': location_id,
                        'location_name': location_name,
                        'default': is_default
                    })
    except Exception:
        saved = []
    return saved


